package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.service.model.TotaalBedragPerSnummerEjt;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.jdbc.core.JdbcTemplate;
import org.springframework.jdbc.core.SqlParameterValue;
import org.springframework.jdbc.support.rowset.SqlRowSet;
import org.springframework.transaction.annotation.Transactional;

import javax.sql.DataSource;
import java.sql.Types;
import java.util.ArrayList;
import java.util.List;

import static be.schaubroeck.lpb.tools.enumtypes.RekenBedragType.BRUTO_MAANDLOON;

@Transactional
public class StandaardEjtAanvraagBerekenService implements EjtAanvraagBerekenService {

    private static final String GET_TOTAL_AMOUNT_PER_S_NUMMER_FOR_EJT = "select r_nummer,sum(rb.bedrag) from rekenhoofd rh " +
            "left join rekenlijn rl on rh.id=rl.rekenhoofdid " +
            "left join rekenbedrag rb on rb.rekenlijnid=rl.id " +
            "left join opdracht_master om on rh.opdrachtid=om.id " +
            "left join persoon_slice ps on ps.persoonid=om.persoonid and year(ps.recordto)=9999 " +
            "left join gl__kode_ext_def ked on ked.ake_id=rl.akeid " +
            "where 1=1 " +
            "and year(rh.begindatum)=? " +
            "and ked.is_ejt=1 " +
            "and rb.bedragtypectid=" + BRUTO_MAANDLOON.getId() +
            " group by 1";
    @Autowired
    private DataSource dataSource;

    @InitializeAdmin
    @Override
    public List<TotaalBedragPerSnummerEjt> getTotaalBedragPerSNummerVoorEjt(Admin admin, Integer jaar) {
        JdbcTemplate jdbc = new JdbcTemplate(dataSource);

        Object[] args = new Object[1];
        args[0] = new SqlParameterValue(Types.INTEGER, jaar);
        SqlRowSet rowSet = jdbc.queryForRowSet(GET_TOTAL_AMOUNT_PER_S_NUMMER_FOR_EJT, args);
        List<TotaalBedragPerSnummerEjt> totaalBedragPerSnummerEjts = new ArrayList<>();
        while (rowSet.next()) {
            TotaalBedragPerSnummerEjt totaalBedragPerSnummerEjt = new TotaalBedragPerSnummerEjt();
            totaalBedragPerSnummerEjt.setSNummer(rowSet.getInt(1));
            totaalBedragPerSnummerEjt.setBelastbaar(new Money(rowSet.getBigDecimal(2)));
            totaalBedragPerSnummerEjts.add(totaalBedragPerSnummerEjt);
        }
        return totaalBedragPerSnummerEjts;
    }
}
